// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.trace;

import static org.assertj.core.api.Assertions.assertThatThrownBy;

import java.util.List;

import org.junit.jupiter.api.Test;

class QueryTraceRecorderTest {

	@Test
	void shouldAllowOneHundredThousandFramesBeforeFailing() {
		QueryTraceRecorder recorder = new QueryTraceRecorder(List.of());

		for (int i = 0; i < 100000; i++) {
			recorder.recordResult(null);
		}

		assertThatThrownBy(() -> recorder.recordResult(null))
				.isInstanceOf(QueryTraceRecorder.TraceLimitExceededException.class)
				.hasMessage("Trace exceeded 100000 frames.");
	}
}
